+  test("Happy path, add correct new multiple contributors", async () => {
+    const mock = nock("https://api.github.com")
+      .get(
+        `/repos/all-contributors/all-contributors-bot/git/ref/heads%2Fall-contributors%2Fadd-gr2m`
+      )
+      .reply(404)
+
